        const dx = p.x - clickX;
        const dy = p.y - clickY;
        const dist = Math.hypot(dx, dy);
        const force = 140 / (dist + 15);
        const angle = Math.atan2(dy, dx);
        p.vx = Math.cos(angle) * force * 16;
        p.vy = Math.sin(angle) * force * 16;
